1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // === Base premiums for main items ===
15	  it.todo("single sword (plain, newcomer, no previous contract) → 100 base + 10 first + 5 fee = 115 G");
16	  it.todo("single amulet (plain, newcomer) → 60 base + 6 first + 5 fee = 71 G");
17	  it.todo("single staff (plain, newcomer) → 80 base + 8 first + 5 fee = 93 G");
18	  it.todo("single potion (plain, newcomer) → 40 base + 4 first + 5 fee = 49 G");
19	
20	  // === Components ===
21	  it.todo("2 runes → 50 G base premium (no block)");
22	  it.todo("3 runes → 60 G base premium (block applies)");
23	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3)");
25	
26	  // === Alike components ===
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	
30	  // === Item-specific modifiers ===
31	  it.todo("cursed sword (steel, ench 3, newcomer) → 100 + 50 curse + 15 first = 165 + 5 fee = 165 G (matches integration example)");
32	  it.todo("sword with enchantment 5 (newcomer) → 100 + 30 high-ench + 13 first + 5 fee = 148 G");
33	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge: 100 + 10 first + 5 fee = 115 G");
34	  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges: 100 + 50 + 30 + 18 first + 5 fee = 203 G");
35	
36	  // === Policy-wide modifiers ===
37	  it.todo("loyalty discount — customer with exactly 2 years → 20% off policy total");
38	  it.todo("loyalty discount does not apply for 1-year customer");
39	  it.todo("follow-up contract — second quote receives 15% discount on policy total");
40	
41	  // === Modifier scope on multi-item policies ===
42	  it.todo("policy with cursed sword + plain amulet → 100 + 60 + 50 curse (item-specific) = 210 before policy-wide and fee");
43	
44	  // === Rounding ===
45	  it.todo("premium that yields 197.5 G → rounded up to 198 G (MHPCO's favor)");
46	  it.todo("payout that yields 350.5 G → rounded down to 350 G (MHPCO's favor)");
47	
48	  // === Claim processing — basic ===
49	  it.todo("standard reimbursement: regular sword (steel, ench 3), damage 500 G → payout 400 G");
50	  it.todo("standard reimbursement: rune (insurance 250 G), damage 200 G → payout 100 G");
51	
52	  // === Claim processing — special clauses ===
53	  it.todo("high enchantment (≥8) damage at 50%: sword ench 8, damage 1000 G → 500 - 100 deductible = 400 G");
54	  it.todo("dragon material full reimbursement: dragon sword ench 5, damage 800 G → 800 - 100 = 700 G");
55	  it.todo("dragon material + ench 9: 50% rule wins then deductible: 500 - 100 = 400 G");
56	  it.todo("dragon material + ench 8 (boundary): 50% then deductible: 500 - 100 = 400 G");
57	  it.todo("steel sword ench 9, damage 1000 G → high-ench: 500 - 100 = 400 G");
58	
59	  // === Deductible per damage event ===
60	  it.todo("dragon attack on sword (500 G) and amulet (300 G) → 600 G payout (deductible applies once per damaged item)");
61	
62	  // === Multiple items of the same type ===
63	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
64	  it.todo("dragon attack on two swords → each damage entry treated separately with own deductible");
65	  it.todo("more damage entries of a type than policy covers → CLI rejects with non-zero exit");
66	
67	  // === Cap exhaustion ===
68	  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
69	  it.todo("cursed sword premium with modifiers doesn't raise cap (cap based on unmodified insurance value)");
70	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G; block affects premium, not insurance sum");
71	  it.todo("sword (cap 2000 G), first claim 1500 → payout 1400, remaining 600");
72	  it.todo("sword (cap 2000 G), second claim 1500 → payout 600, remaining 0");
73	
74	  // === Error cases ===
75	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
76	  it.todo("claim references item not in policy → CLI exits non-zero with error on stderr");
77	  it.todo("claim with negative damage amount → CLI exits non-zero with error on stderr");
78	
79	  // === Integration examples ===
80	  it.todo("integration: newcomer with cursed sword (steel, ench 3) → 165 G");
81	  it.todo("integration: 3-year customer's second quote, cursed sword (steel, ench 7) → 160 G");
82	});
83

1	export const processScenario = (_scenario: unknown): unknown => {
2	  return { results: [{ premium: 5 }] };
3	};
